'use client';
import { useAuth } from '@/context/authContext';
import { useRouter } from 'next/navigation';
import { useEffect, useState, useCallback } from 'react';
import { HomeIcon, CheckCircleIcon, UserGroupIcon, CalendarIcon, BookOpenIcon } from '@heroicons/react/24/outline';
import styles from '@/styles/admin-dashboard.module.css';
import NextLink from '@/components/NextLink';

// Colores
const COLORS = {
  primary: '#10b981',
  secondary: '#06b6d4',
  accent: '#f59e0b',
  danger: '#ef4444',
  success: '#10b981',
  bg: '#0f0f0f',
  surface: '#1b1b1b',
  text: '#ffffff',
  textMuted: '#9ca3af',
};

// Tipos
interface NotaDetalle {
  id: number;
  estudianteId: number;
  materiaId: number;
  periodoId: number;
  descripcion: string;
  valor: number;
  peso: number;
  fecha: string;
}

interface NotasResponse {
  notas: NotaDetalle[];
  promedioPonderado: number;
  totalPeso: number;
}

interface Estudiante {
  id: number;
  name: string;
  email: string;
}

interface Asignacion {
  gradoId: number;
  materiaId: number;
  cicloId: number;
  grado: { id: number; nombre: string; seccion: string };
  materia: { id: number; nombre: string };
  ciclo: { id: number; nombre: string };
}

interface Periodo {
  id: number;
  nombre: string;
}

export default function DocenteNotasPage() {
  const { user } = useAuth();
  const router = useRouter();
  
  // Estados principales
  const [asignaciones, setAsignaciones] = useState<Asignacion[]>([]);
  const [estudiantes, setEstudiantes] = useState<Estudiante[]>([]);
  const [periodos, setPeriodos] = useState<Periodo[]>([]);
  const [selected, setSelected] = useState<Asignacion | null>(null);
  const [periodoId, setPeriodoId] = useState<number | null>(null);
  const [notasEstudiantes, setNotasEstudiantes] = useState<Record<number, NotasResponse>>({});
  const [expandedStudent, setExpandedStudent] = useState<number | null>(null);
  const [nuevaNota, setNuevaNota] = useState({ descripcion: '', valor: 3.0, peso: 10 });
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState("");
  const [docenteInfo, setDocenteInfo] = useState<any>(null);

  const fetchWithAuth = useCallback(async (url: string, options?: RequestInit) => {
    if (!user) throw new Error('Usuario no autenticado');
    const idToken = await user.getIdToken();
    return fetch(url, {
      ...options,
      headers: { ...options?.headers, Authorization: `Bearer ${idToken}` },
    });
  }, [user]);

  // Cargar asignaciones
  useEffect(() => {
    if (!user) return;
    
    (async () => {
      try {
        const res = await fetchWithAuth("/api/docente/asignaciones");
        const data = await res.json();
        setAsignaciones(Array.isArray(data) ? data : []);
      } catch (error) {
        console.error('Error cargando asignaciones:', error);
      }
    })();
  }, [user, fetchWithAuth]);

  // Cargar doctente info
  useEffect(() => {
    if (!user) return;
    
    (async () => {
      try {
        const res = await fetchWithAuth('/api/docente/info');
        const data = await res.json();
        setDocenteInfo(data.docente);
      } catch (error) {
        console.error('Error cargando info:', error);
      }
    })();
  }, [user, fetchWithAuth]);

  // Cargar estudiantes y períodos
  useEffect(() => {
    if (!selected) {
      setEstudiantes([]);
      setPeriodos([]);
      return;
    }
    
    (async () => {
      setLoading(true);
      try {
        const [estudiantesRes, periodosRes] = await Promise.all([
          fetchWithAuth(`/api/docente/estudiantes?gradoId=${selected.gradoId}&materiaId=${selected.materiaId}`),
          fetchWithAuth(`/api/admin/periodos?cicloId=${selected.cicloId}`)
        ]);
        
        const [estData, perData] = await Promise.all([
          estudiantesRes.json(),
          periodosRes.json()
        ]);
        
        setEstudiantes(Array.isArray(estData) ? estData : []);
        setPeriodos(Array.isArray(perData) ? perData : []);
      } catch (error) {
        console.error('Error cargando datos:', error);
      } finally {
        setLoading(false);
      }
    })();
  }, [selected, fetchWithAuth]);

  // Cargar notas del período
  useEffect(() => {
    if (!selected || !periodoId) {
      setNotasEstudiantes({});
      return;
    }
    
    (async () => {
      setLoading(true);
      try {
        const notasObj: Record<number, NotasResponse> = {};
        
        for (const est of estudiantes) {
          try {
            const res = await fetchWithAuth(
              `/api/docente/notas/detalles?estudianteId=${est.id}&materiaId=${selected.materiaId}&periodoId=${periodoId}`
            );
            const data = await res.json();
            notasObj[est.id] = data;
          } catch (error) {
            notasObj[est.id] = { notas: [], promedioPonderado: 0, totalPeso: 0 };
          }
        }
        
        setNotasEstudiantes(notasObj);
      } catch (error) {
        console.error('Error cargando notas:', error);
      } finally {
        setLoading(false);
      }
    })();
  }, [selected, periodoId, estudiantes, fetchWithAuth]);

  // Agregar nota
  const handleAgregarNota = async (estudianteId: number) => {
    if (!nuevaNota.descripcion || nuevaNota.valor < 0 || nuevaNota.valor > 5 || nuevaNota.peso <= 0) {
      setMsg("Verifica los datos: descripción, nota (0-5) y peso (>0)");
      return;
    }
    
    if (!selected || !periodoId) return;
    
    setSaving(true);
    try {
      const idToken = await user!.getIdToken();
      const res = await fetch('/api/docente/notas/detalles', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${idToken}` },
        body: JSON.stringify({
          estudianteId,
          materiaId: selected.materiaId,
          periodoId,
          descripcion: nuevaNota.descripcion,
          valor: nuevaNota.valor,
          peso: nuevaNota.peso
        })
      });
      
      if (res.ok) {
        setMsg("Nota agregada correctamente");
        setNuevaNota({ descripcion: '', valor: 3.0, peso: 10 });
        setExpandedStudent(null);
        
        // Recargar notas
        const reloadRes = await fetchWithAuth(
          `/api/docente/notas/detalles?estudianteId=${estudianteId}&materiaId=${selected.materiaId}&periodoId=${periodoId}`
        );
        const data = await reloadRes.json();
        setNotasEstudiantes(prev => ({ ...prev, [estudianteId]: data }));
      } else {
        setMsg("Error al agregar nota");
      }
    } catch (error) {
      setMsg("Error al agregar nota");
      console.error(error);
    } finally {
      setSaving(false);
    }
  };

  // Eliminar nota
  const handleEliminarNota = async (notaId: number, estudianteId: number) => {
    if (!confirm('¿Eliminar esta nota?')) return;
    
    setSaving(true);
    try {
      const idToken = await user!.getIdToken();
      const res = await fetch(`/api/docente/notas/detalles?notaId=${notaId}`, {
        method: 'DELETE',
        headers: { Authorization: `Bearer ${idToken}` }
      });
      
      if (res.ok) {
        setMsg("Nota eliminada correctamente");
        
        // Actualizar state
        if (selected && periodoId) {
          const reloadRes = await fetchWithAuth(
            `/api/docente/notas/detalles?estudianteId=${estudianteId}&materiaId=${selected.materiaId}&periodoId=${periodoId}`
          );
          const data = await reloadRes.json();
          setNotasEstudiantes(prev => ({ ...prev, [estudianteId]: data }));
        }
      } else {
        setMsg("Error al eliminar nota");
      }
    } catch (error) {
      setMsg("Error al eliminar nota");
      console.error(error);
    } finally {
      setSaving(false);
    }
  };

  const handleLogout = useCallback(async () => {
    await logout();
    router.push('/login');
  }, [logout, router]);

  return (
    <div className={styles.dashboardContainer}>
      {/* Sidebar */}
      <aside className={styles.sidebar}>
        <div style={{ display: 'flex', alignItems: 'center', marginBottom: '3rem' }}>
          <div style={{
            width: '40px',
            height: '40px',
            borderRadius: '50%',
            background: `linear-gradient(135deg, ${COLORS.primary}, ${COLORS.secondary})`,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            fontWeight: 'bold',
            color: '#000',
            marginRight: '0.75rem'
          }}>
            A
          </div>
          <span style={{ fontSize: '1.25rem', fontWeight: 'bold', color: COLORS.primary }}>AulaUnida</span>
        </div>

        <div style={{
          backgroundColor: `${COLORS.secondary}20`,
          border: `1px solid ${COLORS.secondary}30`,
          borderRadius: '0.75rem',
          padding: '0.75rem',
          marginBottom: '2rem'
        }}>
          <div style={{
            width: '48px',
            height: '48px',
            borderRadius: '50%',
            backgroundColor: COLORS.secondary,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            color: '#000',
            fontWeight: 'bold',
            marginBottom: '0.5rem'
          }}>
            {user?.displayName?.charAt(0)?.toUpperCase() || 'T'}
          </div>
          <p style={{ margin: '0.25rem 0 0', fontWeight: 600, fontSize: '0.9rem', color: COLORS.text }}>
            {user?.displayName || 'Docente'}
          </p>
          <div style={{
            display: 'inline-block',
            backgroundColor: COLORS.secondary,
            color: '#000',
            padding: '0.2rem 0.5rem',
            borderRadius: '0.25rem',
            fontSize: '0.65rem',
            fontWeight: 700,
            marginTop: '0.25rem'
          }}>
            DOCENTE
          </div>
        </div>

        <nav style={{ marginBottom: '2rem' }}>
          <ul style={{ listStyle: 'none', padding: 0, margin: 0, display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
            {[
              { label: 'Dashboard', href: '/docente' },
              { label: 'Mis Tareas', href: '/docente/tareas' },
              { label: 'Asistencia', href: '/docente/asistencia' },
              { label: 'Asignar Notas', href: '/docente/notas' }
            ].map(link => (
              <li key={link.href}>
                <a href={link.href} style={{
                  display: 'flex',
                  alignItems: 'center',
                  padding: '0.75rem 1rem',
                  borderRadius: '0.5rem',
                  color: link.href === '/docente/notas' ? COLORS.primary : COLORS.textMuted,
                  textDecoration: 'none',
                  backgroundColor: link.href === '/docente/notas' ? `${COLORS.primary}15` : 'transparent',
                  fontWeight: link.href === '/docente/notas' ? 600 : 400,
                  transition: 'all 0.2s',
                  borderLeft: link.href === '/docente/notas' ? `3px solid ${COLORS.primary}` : '3px solid transparent'
                }}>
                  {link.label}
                </a>
              </li>
            ))}
          </ul>
        </nav>

        <button onClick={handleLogout} style={{
          width: '100%',
          padding: '0.75rem',
          backgroundColor: `${COLORS.danger}20`,
          color: COLORS.danger,
          border: `1px solid ${COLORS.danger}40`,
          borderRadius: '0.5rem',
          fontWeight: 600,
          cursor: 'pointer'
        }}>
          ⎋ Cerrar sesión
        </button>
      </aside>

      {/* Main */}
      <main className={styles.mainContent}>
        <h1 className={styles.title}>Asignación de Notas</h1>
        <p className={styles.subtitle}>
          {docenteInfo ? `Gestiona las notas de tus estudiantes, ${docenteInfo.name}` : 'Sistema de notas con pesos y porcentajes'}
        </p>

        <div className={styles.activityCard} style={{ backgroundColor: COLORS.surface, border: `1px solid ${COLORS.primary}20` }}>
          <h2 style={{ color: COLORS.text, marginBottom: '1.5rem', fontSize: '1.25rem', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
            📋 Seleccionar Grupo y Período
          </h2>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem', marginBottom: '2rem' }}>
            <div>
              <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: 600, color: COLORS.text }}>
                Grupo y Materia:
              </label>
              <select
                value={selected ? `${selected.gradoId}-${selected.materiaId}` : ''}
                onChange={(e) => {
                  const [gradoId, materiaId] = e.target.value.split('-');
                  const a = asignaciones.find(x => x.gradoId === parseInt(gradoId) && x.materiaId === parseInt(materiaId));
                  setSelected(a || null);
                  setPeriodoId(null);
                }}
                style={{
                  width: '100%',
                  padding: '0.75rem',
                  borderRadius: '0.5rem',
                  border: `1px solid ${COLORS.primary}40`,
                  background: COLORS.bg,
                  color: COLORS.text,
                  cursor: 'pointer'
                }}
              >
                <option value="">Selecciona grupo y materia...</option>
                {asignaciones.map(a => (
                  <option key={`${a.gradoId}-${a.materiaId}`} value={`${a.gradoId}-${a.materiaId}`}>
                    {a.grado.nombre} {a.grado.seccion} - {a.materia.nombre}
                  </option>
                ))}
              </select>
            </div>

            {selected && (
              <div>
                <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: 600, color: COLORS.text }}>
                  Período:
                </label>
                <select
                  value={periodoId || ''}
                  onChange={(e) => setPeriodoId(e.target.value ? parseInt(e.target.value) : null)}
                  style={{
                    width: '100%',
                    padding: '0.75rem',
                    borderRadius: '0.5rem',
                    border: `1px solid ${COLORS.secondary}40`,
                    background: COLORS.bg,
                    color: COLORS.text,
                    cursor: 'pointer'
                  }}
                >
                  <option value="">Selecciona período...</option>
                  {periodos.map(p => (
                    <option key={p.id} value={p.id}>
                      {p.nombre}
                    </option>
                  ))}
                </select>
              </div>
            )}
          </div>

          {/* Estudiantes */}
          {selected && periodoId && !loading && estudiantes.length > 0 && (
            <div>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem', paddingBottom: '1rem', borderBottom: `2px solid ${COLORS.primary}40` }}>
                <h3 style={{ color: COLORS.text, fontSize: '1.15rem', margin: 0 }}>
                  👥 Estudiantes de {selected.grado.nombre} {selected.grado.seccion}
                </h3>
                <span style={{ color: COLORS.textMuted, fontSize: '0.9rem' }}>
                  <span style={{ color: COLORS.primary }}>●</span> {estudiantes.length} estudiantes
                </span>
              </div>

              <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                {estudiantes.map(est => {
                  const notasData = notasEstudiantes[est.id] || { notas: [], promedioPonderado: 0, totalPeso: 0 };
                  const isExpanded = expandedStudent === est.id;
                  
                  return (
                    <div
                      key={est.id}
                      style={{
                        backgroundColor: COLORS.bg,
                        border: `1px solid ${COLORS.primary}20`,
                        borderRadius: '0.75rem',
                        padding: '1.25rem',
                        transition: 'all 0.2s'
                      }}
                    >
                      {/* Encabezado del estudiante */}
                      <div style={{ display: 'grid', gridTemplateColumns: '2fr 1.5fr 1fr', gap: '1rem', alignItems: 'center', marginBottom: isExpanded ? '1rem' : 0 }}>
                        <div>
                          <div style={{ color: COLORS.text, fontWeight: 600, fontSize: '1rem', marginBottom: '0.25rem' }}>
                            {est.name}
                          </div>
                          <div style={{ color: COLORS.textMuted, fontSize: '0.85rem' }}>
                            {est.email}
                          </div>
                        </div>

                        {/* Notas */}
                        <div style={{ display: 'flex', flexWrap: 'wrap', gap: '0.5rem' }}>
                          {notasData.notas.length > 0 ? (
                            notasData.notas.map(nota => (
                              <div key={nota.id} style={{
                                backgroundColor: `${COLORS.secondary}20`,
                                border: `1px solid ${COLORS.secondary}40`,
                                borderRadius: '0.5rem',
                                padding: '0.4rem 0.6rem',
                                fontSize: '0.8rem',
                                color: COLORS.secondary,
                                fontWeight: 600
                              }}>
                                {nota.valor.toFixed(1)} ({nota.peso}%)
                              </div>
                            ))
                          ) : (
                            <span style={{ color: COLORS.textMuted, fontSize: '0.9rem' }}>Sin notas</span>
                          )}
                        </div>

                        {/* Promedio */}
                        <div style={{
                          textAlign: 'center',
                          padding: '0.5rem',
                          backgroundColor: notasData.promedioPonderado > 0 ? `${COLORS.primary}15` : `${COLORS.textMuted}10`,
                          borderRadius: '0.5rem',
                          border: `1px solid ${notasData.promedioPonderado > 0 ? COLORS.primary : COLORS.textMuted}20`
                        }}>
                          <div style={{ fontSize: '0.75rem', color: COLORS.textMuted }}>Promedio</div>
                          <div style={{
                            color: notasData.promedioPonderado >= 3.0 ? COLORS.primary : notasData.promedioPonderado > 0 ? COLORS.accent : COLORS.textMuted,
                            fontWeight: 700,
                            fontSize: '1.25rem'
                          }}>
                            {notasData.promedioPonderado > 0 ? notasData.promedioPonderado.toFixed(2) : '--'}
                          </div>
                        </div>
                      </div>

                      {/* Botón expandir */}
                      {notasData.notas.length > 0 && (
                        <div style={{ marginTop: '1rem', borderTop: `1px solid ${COLORS.primary}20`, paddingTop: '1rem' }}>
                          <button
                            onClick={() => setExpandedStudent(isExpanded ? null : est.id)}
                            style={{
                              background: 'none',
                              border: 'none',
                              color: COLORS.secondary,
                              cursor: 'pointer',
                              fontWeight: 600,
                              fontSize: '0.9rem'
                            }}
                          >
                            {isExpanded ? '▼ Contraer' : '▶ Ver detalles'}
                          </button>
                        </div>
                      )}

                      {/* Detalles de notas (expandido) */}
                      {isExpanded && notasData.notas.length > 0 && (
                        <div style={{ marginTop: '1rem', paddingTop: '1rem', borderTop: `1px solid ${COLORS.primary}20` }}>
                          <h4 style={{ color: COLORS.text, margin: '0 0 0.75rem', fontSize: '0.95rem' }}>Notas detalladas:</h4>
                          <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                            {notasData.notas.map(nota => (
                              <div
                                key={nota.id}
                                style={{
                                  display: 'flex',
                                  justifyContent: 'space-between',
                                  alignItems: 'center',
                                  padding: '0.75rem',
                                  backgroundColor: `${COLORS.surface}80`,
                                  borderRadius: '0.5rem',
                                  border: `1px solid ${COLORS.primary}20`
                                }}
                              >
                                <div style={{ flex: 1 }}>
                                  <div style={{ color: COLORS.text, fontWeight: 600, fontSize: '0.9rem' }}>
                                    {nota.descripcion}
                                  </div>
                                  <div style={{ color: COLORS.textMuted, fontSize: '0.8rem' }}>
                                    Nota: {nota.valor.toFixed(1)}/5.0 • Peso: {nota.peso}%
                                  </div>
                                </div>
                                <button
                                  onClick={() => handleEliminarNota(nota.id, est.id)}
                                  disabled={saving}
                                  style={{
                                    padding: '0.4rem 0.8rem',
                                    backgroundColor: `${COLORS.danger}20`,
                                    color: COLORS.danger,
                                    border: `1px solid ${COLORS.danger}40`,
                                    borderRadius: '0.4rem',
                                    cursor: 'pointer',
                                    fontSize: '0.8rem',
                                    fontWeight: 600
                                  }}
                                >
                                  Eliminar
                                </button>
                              </div>
                            ))}
                          </div>
                        </div>
                      )}

                      {/* Formulario agregar nota */}
                      {isExpanded || notasData.notas.length === 0 ? (
                        <div style={{ marginTop: '1rem', paddingTop: '1rem', borderTop: `1px solid ${COLORS.primary}20` }}>
                          <h4 style={{ color: COLORS.text, margin: '0 0 1rem', fontSize: '0.95rem' }}>
                            + Agregar Nueva Nota
                          </h4>
                          <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr 1fr auto', gap: '0.75rem', alignItems: 'flex-end' }}>
                            <input
                              type="text"
                              placeholder="Descripción (ej: Quiz 1, Evaluación Final)"
                              value={nuevaNota.descripcion}
                              onChange={(e) => setNuevaNota({ ...nuevaNota, descripcion: e.target.value })}
                              style={{
                                padding: '0.6rem',
                                borderRadius: '0.5rem',
                                border: `1px solid ${COLORS.primary}40`,
                                background: COLORS.surface,
                                color: COLORS.text,
                                fontSize: '0.9rem'
                              }}
                            />
                            <input
                              type="number"
                              min="0"
                              max="5"
                              step="0.1"
                              placeholder="Nota (0-5)"
                              value={nuevaNota.valor}
                              onChange={(e) => setNuevaNota({ ...nuevaNota, valor: parseFloat(e.target.value) || 0 })}
                              style={{
                                padding: '0.6rem',
                                borderRadius: '0.5rem',
                                border: `1px solid ${COLORS.primary}40`,
                                background: COLORS.surface,
                                color: COLORS.text,
                                fontSize: '0.9rem'
                              }}
                            />
                            <input
                              type="number"
                              min="0"
                              max="100"
                              placeholder="Peso %"
                              value={nuevaNota.peso}
                              onChange={(e) => setNuevaNota({ ...nuevaNota, peso: parseFloat(e.target.value) || 0 })}
                              style={{
                                padding: '0.6rem',
                                borderRadius: '0.5rem',
                                border: `1px solid ${COLORS.primary}40`,
                                background: COLORS.surface,
                                color: COLORS.text,
                                fontSize: '0.9rem'
                              }}
                            />
                            <button
                              onClick={() => handleAgregarNota(est.id)}
                              disabled={saving}
                              style={{
                                padding: '0.6rem 1rem',
                                backgroundColor: COLORS.primary,
                                color: '#000',
                                border: 'none',
                                borderRadius: '0.5rem',
                                fontWeight: 600,
                                cursor: saving ? 'not-allowed' : 'pointer',
                                opacity: saving ? 0.6 : 1
                              }}
                            >
                              {saving ? '...' : 'Agregar'}
                            </button>
                          </div>
                        </div>
                      ) : (
                        <div style={{ marginTop: '1rem', paddingTop: '1rem', borderTop: `1px solid ${COLORS.primary}20` }}>
                          <button
                            onClick={() => setExpandedStudent(est.id)}
                            style={{
                              padding: '0.6rem 1rem',
                              backgroundColor: `${COLORS.primary}20`,
                              color: COLORS.primary,
                              border: `1px solid ${COLORS.primary}40`,
                              borderRadius: '0.5rem',
                              fontWeight: 600,
                              cursor: 'pointer',
                              fontSize: '0.9rem'
                            }}
                          >
                            + Agregar Nota
                          </button>
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {loading && <div style={{ textAlign: 'center', padding: '2rem', color: COLORS.textMuted }}>⏳ Cargando...</div>}
          
          {!loading && selected && periodoId && estudiantes.length === 0 && (
            <div style={{ textAlign: 'center', padding: '2rem', color: COLORS.textMuted }}>
              No hay estudiantes en este grupo
            </div>
          )}

          {msg && (
            <div style={{
              marginTop: '1.5rem',
              padding: '1rem',
              backgroundColor: msg.includes('Error') ? `${COLORS.danger}15` : `${COLORS.success}15`,
              border: `1px solid ${msg.includes('Error') ? COLORS.danger : COLORS.success}30`,
              color: msg.includes('Error') ? COLORS.danger : COLORS.success,
              borderRadius: '0.5rem',
              fontSize: '0.9rem'
            }}>
              {msg.includes('Error') ? '❌' : '✅'} {msg}
            </div>
          )}

          <div style={{
            marginTop: '1.5rem',
            padding: '1rem',
            backgroundColor: `${COLORS.secondary}10`,
            borderLeft: `3px solid ${COLORS.secondary}`,
            borderRadius: '0.25rem',
            fontSize: '0.85rem',
            color: COLORS.textMuted
          }}>
            💡 <strong>Consejos:</strong> Puedes agregar ilimitadas notas por periodo. El promedio se calcula automáticamente según los pesos. Los pesos indican el porcentaje que aporta cada nota al promedio final.
          </div>
        </div>
      </main>
    </div>
  );
}
